+          filename: '[name]-3.js',
+          chunkFilename: '[id]-3.[name].js',
+        },
+        optimization: {
+          minimize: false,
+        },
+        plugins: [
+          new SourceMapDevToolPlugin({
+            filename: '[file].map[query]',
+            module: false,
+            columns: false,
+          }),
+          new TerserPlugin(),
+        ],
+      },
+      {
+        mode: 'production',
+        bail: true,
+        cache: false,
+        devtool: false,
+        entry: `${__dirname}/fixtures/entry.js`,
+        output: {
+          path: `${__dirname}/dist`,
+          filename: '[name]-4.js',
+          chunkFilename: '[id]-4.[name].js',
+        },
+        optimization: {
+          minimize: false,
+        },
+        plugins: [
+          new SourceMapDevToolPlugin({
+            filename: '[file].map[query]',
+            module: true,
+            columns: true,
+          }),
+          new TerserPlugin(),
+        ],
+      },
+    ]);
+
+    const multiStats = await compile(multiCompiler);
+
+    multiStats.stats.forEach((stats, index) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('errors');
+      expect(warnings).toMatchSnapshot('warnings');
+      expect(getAssets(stats, multiCompiler.compilers[index])).toMatchSnapshot(
+        'assets'
+      );
+    });
+  });
 });

