diff --git a/test/chunkFilter-option.test.js b/test/chunkFilter-option.test.js
new file mode 100644
index 0000000..e738d55
--- /dev/null
+++ b/test/chunkFilter-option.test.js
@@ -0,0 +1,44 @@
+import TerserPlugin from '../src/index';
+
+import { cleanErrorStack, createCompiler, compile } from './helpers';
+
+describe('when applied with `chunkFilter` option', () => {
+  let compiler;
+
+  beforeEach(() => {
+    compiler = createCompiler({
+      entry: {
+        included: `${__dirname}/fixtures/included1.js`,
+        entry: `${__dirname}/fixtures/entry.js`,
+      },
+    });
+  });
+
+  it('matches snapshot for a single `chunkFilter`', () => {
+    new TerserPlugin({
+      chunkFilter: (chunk) => {
+        if (chunk.name === 'included') {
+          return false;
+        }
+
+        return true;
+      },
+    }).apply(compiler);
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('errors');
+      expect(warnings).toMatchSnapshot('warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (
+          Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)
+        ) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+        }
+      }
+    });
+  });
+});

diff --git a/test/validation.test.js b/test/validation.test.js
index 41790f6..b3a5d74 100644
--- a/test/validation.test.js
+++ b/test/validation.test.js
@@ -99,6 +99,14 @@ it('validation', () => {
   }).toThrowErrorMatchingSnapshot();

   expect(() => {
+    new TerserPlugin({ chunkFilter: () => {} });
+  }).not.toThrow();
+
+  expect(() => {
+    new TerserPlugin({ chunkFilter: true });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
     new TerserPlugin({ cache: true });
   }).not.toThrow();

